def decodeEitherType(et: hydra.core.EitherType): hydra.core.Term =
  {
  lazy val leftDecoder: hydra.core.Term = hydra.decoding.decodeType(et.left)
  lazy val rightDecoder: hydra.core.Term = hydra.decoding.decodeType(et.right)
  hydra.core.Term.application(hydra.core.Application(hydra.core.Term.application(hydra.core.Application(hydra.core.Term.variable("hydra.extract.helpers.decodeEither"), leftDecoder)), rightDecoder))
}

def decodeForallType(ft: hydra.core.ForallType): hydra.core.Term =
  hydra.core.Term.function(hydra.core.Function.lambda(hydra.core.Lambda(hydra.decoding.decodeBindingName(ft.parameter), None, hydra.decoding.decodeType(ft.body))))

def decodeListType(elemType: hydra.core.Type): hydra.core.Term =
  {
  lazy val elemDecoder: hydra.core.Term = hydra.decoding.decodeType(elemType)
  hydra.core.Term.application(hydra.core.Application(hydra.core.Term.variable("hydra.extract.helpers.decodeList"), elemDecoder))
}

